<script>
    import Charts from './Chart'
    import Multiselect from 'vue-multiselect'
    import Loading from 'vue-loading-overlay';
    import 'vue-loading-overlay/dist/vue-loading.css';
    import UnitsMovedComponent from "./partial/UnitsMovedComponent";
    import note from "./partial/Note";
    import CmBanner from "./partial/CmBanner";
    import ZatcaBanner from "./partial/ZatcaBanner";
    import Contact from "./partial/Contact";
    import MessageDisplay from './partial/MessageDisplay.vue';

    export default {
        name: "card",
        components: {
            Charts,
            Multiselect,
            Loading,
            UnitsMovedComponent,
            Contact,
            note,
            CmBanner,
            ZatcaBanner,
            MessageDisplay
        },
        props: [
            'card'
        ],
        data: () => {
            return {
                showSteps: false,
                price_type: 'Day',
                loading: true,
                calculationsActive : true,
                emptyUnits: true,
                date: moment().format('YYYY-MM-DD'),
                safe_balance: null,
                occupied_percentage: 0,
                available_units: 0,
                datePicker: moment(moment().format('YYYY-MM-DD')).toDate(),
                selected: {
                    types: [],
                    special_features: [],
                    general_features: [],
                    status: []
                },
                options: {
                    types: ['list', 'of', 'options'],
                    special_features: ['list', 'of', 'options'],
                    general_features: ['list', 'of', 'options'],
                    status: ['list', 'of', 'options'],
                },
                crumbs: [],
                locale: 'en',
                noteBody: null,
                occupied_percentage_today : 0,
                units: [],
                page: 1,
                settings_count : null,
                units_count : null,
                currentUserName : null,
                awaitingPaymentReservationsCount : 0,
                counters : {},
                isCallingOccupied : false,
                integration_shms : Spark.state.currentTeam.integration_shms,
                show_shms_alert : false,
                payment_preprocessor : Spark.state.currentTeam.payment_preprocessor,
                hasPermissionToViewSettings : Nova.app.$hasPermission('view settings'),
                teamId : Spark.state.currentTeam.id,
                remaining_interval : null
            }
        },
        created() {
           this.getNotificationSteps();
        },
        methods: {
            gotoIntegration(){
                if (this.hasPermissionToViewSettings) {
                    this.$router.push('/settings/integrations')
                }

            },
            fetchCaclculations(){

                Nova.request().get('/nova-vendor/calender/calculations?date=' + this.date)
                    .then((res) => {
                        if(res.data.gte){
                            this.available_units = res.data.available_units;
                            this.occupied_percentage = res.data.occupied_percentage;
                            this.occupied_percentage_today = res.data.occupied_percentage;
                        }else{
                            this.available_units = res.data.available_units;
                            this.occupied_percentage = res.data.occupied_percentage;
                        }
                        this.safe_balance = res.data.safe_balance;
                        this.calculationsActive = false;
                    })
            },
            scrollDownToOnlineReservations(){
                let container = this.$refs.awaitingList;
                container.scrollIntoView();
            },
            resetDatetoToday(){
                this.datePicker =  moment(moment().format('YYYY-MM-DD')).toDate();
                this.update();
            },
            hideSteps(){
                this.showSteps = false;
            },


            getNotificationSteps(){
                Nova.request().get('/nova-vendor/calender/notification-steps')
                    .then((res) => {
                        this.settings_count = res.data.settings_count;
                        this.units_count = res.data.units_count;

                        if(this.settings_count > 2 && this.units_count > 1){
                            this.showSteps = false;
                        }else{
                            this.showSteps = true;
                        }
                    })
            },
            noteChanged() {
                this.noteBody = this.$refs.noteInput.value;
            },
            addNote() {
                axios.post('/apidata/notes', {
                    body: this.noteBody
                }).then(res => {
                    this.btnNotes()
                    this.noteBody = null;
                    this.$refs.noteInput.value = null;
                    this.$toasted.success(this.__('Note added successfully'), {
                        duration: 3000
                    })
                })
            },
            end() {
                let date = Spark.state.currentTeam.trial_ends_at;
                if (date == null) {
                    date = Spark.state.currentTeam.ends_at;
                }
                return !moment(date).isSameOrAfter(moment()) && Spark.state.currentTeam.current_billing_plan != 'team-free';
            },
            trial() {
                let date = Spark.state.currentTeam.trial_ends_at;
                if (date == null) {
                    date = Spark.state.currentTeam.ends_at;
                }
                return moment(date).diff(moment(), 'days') <= 30 && Spark.state.currentTeam.current_billing_plan != 'team-free';
            },
            update() {
                this.loading = true;
                // console.log("this.datePicker", this.datePicker)

                if (this.datePicker === null) {
                    this.datePicker = moment(this.date).toDate()
                    return;
                }

                // console.log("this.date b", this.date)

                this.date = moment(String(this.datePicker)).format('YYYY-MM-DD')
                //  console.log("this.date a", this.date)
                this.crumbs = [
                    {
                        text: 'Home',
                        to: 'home',
                    },
                    {
                        text: 'Calender',
                        to: '/calender',
                    },
                    {
                        text: this.date,
                        to: 'date',
                    }
                ]

                this.$el.querySelector('#date-input').value = Nova.app.__formatDateWithHijriDate(this.date);
            },
            btnNotes() {
                $('#showaddnotes').toggleClass('active');
            },
        },
        mounted() {
            this.currentUserName =  Nova.app.user.name;
            this.locale = Nova.config.local;
            this.crumbs = [
                {
                    text: 'Home',
                    to: 'home',
                },
                {
                    text: 'Calender',
                    to: '/calender',
                },
                {
                    text: this.date,
                    to: 'date',
                }
            ];

            if(this.payment_preprocessor == 'sure-bills'){
                Nova.$emit('call-awaiting-payment-reservations-query');
            }

            if(this.payment_preprocessor == 'fandaqah'){
                Nova.$emit('call-awaiting-confirmation-reservations-query');
            }

            this.fetchCaclculations();

            $('button.search_multi_select').append('<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 451 451"><path d="M447.05 428l-109.6-109.6c29.4-33.8 47.2-77.9 47.2-126.1C384.65 86.2 298.35 0 192.35 0 86.25 0 .05 86.3.05 192.3s86.3 192.3 192.3 192.3c48.2 0 92.3-17.8 126.1-47.2L428.05 447c2.6 2.6 6.1 4 9.5 4s6.9-1.3 9.5-4c5.2-5.2 5.2-13.8 0-19zM26.95 192.3c0-91.2 74.2-165.3 165.3-165.3 91.2 0 165.3 74.2 165.3 165.3s-74.1 165.4-165.3 165.4c-91.1 0-165.3-74.2-165.3-165.4z"/></svg>');

            // // Set the date we're counting down to
            // var countDownDate = new Date("Aug 9, 2023 05:00:00").getTime();

            // // Update the count down every 1 second
            // var x = setInterval(function() {

            // // Get today's date and time
            // var now = new Date().getTime();

            // // Find the distance between now and the count down date
            // var distance = countDownDate - now;

            // // Time calculations for days, hours, minutes and seconds
            // var days = Math.floor(distance / (1000 * 60 * 60 * 24));
            // var hours = Math.floor((distance % (1000 * 60 * 60 * 24)) / (1000 * 60 * 60));
            // var minutes = Math.floor((distance % (1000 * 60 * 60)) / (1000 * 60));
            // var seconds = Math.floor((distance % (1000 * 60)) / 1000);

            // // $('button#emad_btn').text(days + "d " + hours + "h " + minutes + "m " + seconds + "s ");
            // if(Nova.config.local == 'en'){
            //     $('#remaining_time_to_schedule').text('- ' + Nova.app.__('Remaining Time : ') + days + " d " + hours + " h " + minutes + " m " + seconds + " s ");
            // }else{
            //     $('#remaining_time_to_schedule').text('- ' + Nova.app.__('Remaining Time : ') + days + " يوم " + hours + " ساعة " + minutes + " دقيقة " + seconds + " ثانية ");
            // }
            // // If the count down is over, write some text
            // if (distance < 0) {
            //     clearInterval(x);
            //     // document.getElementById("demo").innerHTML = "EXPIRED";
            // }
            // }, 1000);


        },
    }
</script>

