                                  [dir="ltr"] & {
                                      padding: 7px 10px 7px 25px;
                                  } /* ltr */
                              }
                              &::before {
                                  content: "";
                                  height: 14px;
                                  background: #fff;
                                  word-wrap: 14px;
                                  display: inline-block;
                                  width: 14px;
                                  margin: 0 0 0 5px;
                                  position: relative;
                                  top: 3px;
                                  border-radius: 2px;
                                  border: 1px solid #ddd;
                                  [dir="ltr"] & {
                                      margin: 0 5px 0 0;
                                  } /* ltr */
                                  @media (min-width: 320px) and (max-width: 767px) {
                                      position: absolute;
                                      right: 5px;
                                      top: 9px;
                                      margin: 0 auto;
                                      [dir="ltr"] & {
                                          left: 5px;
                                          right: auto;
                                      } /* ltr */
                                  }
                              } /* before */
                              &::after {display: none;}
                              &.multiselect__option--highlight {
                                  background: #fafafa;
                                  &::after{display: none;}
                              } /* multiselect__option--highlight */
                              &.multiselect__option--selected {
                                  font-weight: normal;
                                  color: #0A80D8;
                                  &::before {
                                      background: #0A80D8;
                                      border-color: #0A80D8;
                                  } /* before */
                              } /* multiselect__option--selected */
                          } /* multiselect__option */
                          &:first-child {
                              span.multiselect__option {border-top: none;}
                          } /* first-child */
                      } /* multiselect__element */
                  } /* li */
              } /* multiselect__content-wrapper */
          } /* multiselect */
          .actionButton {
              @media (min-width: 320px) and (max-width: 767px) {
                  display: flex;
                  width: 100%;
                  justify-content: center;
              }
              button[type="submit"] {
                  float: right;
                  height: 35px;
                  background: #0A80D8;
                  padding: 0;
                  border-radius: 3px;
                  font-size: 0px;
                  color: #fff;
                  margin: 0 0 0 10px;
                  width: 35px;
                  -webkit-transition: all 0.2s ease-in-out;
                  -moz-transition: all 0.2s ease-in-out;
                  -o-transition: all 0.2s ease-in-out;
                  transition: all 0.2s ease-in-out;
                  [dir="ltr"] & {
                      float: left;
                      margin: 0 10px 0 0;
                  } /* ltr */
                  @media (min-width: 320px) and (max-width: 767px) {
                      float: none;
                  }
                  &:hover {background: #0071C9;}
                  svg {
                      height: 20px;
                      margin: 0 auto;
                      fill: #fff;
                  } /* svg */
              } /* button */
              button[type="reset"] {
                  float: right;
                  height: 35px;
                  background: #718096;
                  padding: 0;
                  border-radius: 3px;
                  font-size: 17px;
                  border: 1px solid #718096;
                  margin: 0;
                  width: 35px;
                  text-align: center;
                  -webkit-transition: all 0.2s ease-in-out;
                  -moz-transition: all 0.2s ease-in-out;
                  -o-transition: all 0.2s ease-in-out;
                  transition: all 0.2s ease-in-out;
                  [dir="ltr"] & {
                      float: left;
                  } /* ltr */
                  @media (min-width: 320px) and (max-width: 767px) {
                      float: none;
                  }
                  &:hover {
                      background: #627187;
                      border-color: #627187;
                  } /* hover */
                  svg {
                      display: block;
                      margin: 0 auto;
                      fill: #ffffff;
                  } /* svg */
              } /* button */
          } /* actionButton */
      } /* choose_area */
      .waiting_reservations {
        span {
          display: block;
          cursor: pointer;
          background-size: 21px;
          background-repeat: no-repeat;
          background-position: center right;
          font-size: 15px;
          padding: 0 28px 0 0;
          background-image: url("/images/alert_icon.gif");
          line-height: 30px;
        } /* span */
      } /* waiting_reservations */
      .units_info {
          @media (min-width: 320px) and (max-width: 767px) {
              margin: 10px 0;
              display: flex;
              justify-content: space-between;
              width: 100%;
          }
          span {
              display: inline-block;
              font-size: 15px;
              margin: 0 0 0 40px;
              [dir="ltr"] & {
                  margin: 0 40px 0 0;
              } /* ltr */
              @media (min-width: 320px) and (max-width: 767px) {
                  width: auto;
                  margin: 0 auto;
                  [dir="ltr"] & {
                      margin: 0 auto;
                  } /* ltr */
              }
              &:last-of-type {margin: 0 auto;}
          } /* span */
      } /* units_info */
  } /* filter_search_homapage */

