  .main_calendar_area {
      position: relative;
      display: flex;
      justify-content: space-between;
      align-items: center;
      flex-wrap: wrap;
      .col_date {
          display: flex;
          align-items: center;
          justify-content: flex-start;
          flex-wrap: wrap;
          margin: 15px 0;
          i {
              font-size: 21px;
              margin: 0 0 0 10px;
          } /* i */
          input#date-input {
              background: transparent;
              border: none;
              padding: 0;
              font-size: 20px;
              min-width: 400px;
              color: #000;
              @media (min-width: 320px) and (max-width: 767px) {
                  font-size: 15px;
                  min-width: 290px;
              }
          } /* input */
      } /* col_date */
      .col_today {
          margin: 15px 0;
          @media (min-width: 320px) and (max-width: 767px) {
              margin: 0 auto;
          }
          button {
              color: #fff;
              background-color: #2C3E50;
              opacity: 0.65;
              display: inline-block;
              font-weight: 400;
              text-align: center;
              vertical-align: middle;
              user-select: none;
              border: 1px solid transparent;
              padding: 0.4em 0.65em;
              font-size: 1em;
              line-height: 1.5;
              border-radius: 0.25em;
              &:hover {
                  background: #1D2F41;
              } /* hover */
          } /* button */
      } /* col_today */
  } /* main_calendar_area */
  .chart_labels_balance {
      background: #fff;
      padding: 15px;
      margin: 15px auto;
      border-radius: 4px;
      display: flex;
      justify-content: space-between;
      align-items: center;
      box-shadow: 0 1px 3px 0 rgba(0,0,0,.1),0 1px 2px 0 rgba(0,0,0,.06);
      @media (min-width: 320px) and (max-width: 767px) {
          display: block;
          text-align: center;
          padding: 10px;
      }
      .labels {
          @media (min-width: 320px) and (max-width: 767px) {
              width: 100%;
          }
          ul {
              display: flex;
              flex-wrap: wrap;
              li {
                  margin: 0 0 0 20px;
                  font-size: 15px;
                  line-height: 15px;
                  [dir="ltr"] & {
                      margin: 0 20px 0 0;
                  } /* ltr */
                  @media (min-width: 320px) and (max-width: 767px) {
                      width: 33.333%;
                      margin: 0 auto 15px;
                      text-align: initial;
                  }
                  i {
                      float: right;
                      height: 15px;
                      width: 15px;
                      margin: 0 0 0 5px;
                      [dir="ltr"] & {
                          float: left;
                          margin: 0 5px 0 0;
                      } /* ltr */
                  } /* i */
                  &.empty i {background: #50c669;}
                  &.checkedin i {background: #f6574b;}
                  &.reserved i {background: #126ee8;}
                  &.onlinewaiting i {background: #9B59B6;}
                  &.cleanliness i {background: #ff9019;}
                  &.maintenance i {background: #b3c0c7;}
              } /* li */
          } /* ul */
      } /* labels */
      .safe_balance_text {
          font-size: 15px;
          @media (min-width: 320px) and (max-width: 767px) {
              width: 100%;
          }
      } /* safe_balance_text */
  } /* main_calendar_area */
  .units-dash-home {
      margin: 0 -.5rem;
      display: grid;
      grid-template-columns: repeat(auto-fill,minmax(195px, 1fr));
      @media (min-width: 320px) and (max-width: 480px) {
          margin: .5rem -.5rem;
          grid-template-columns: repeat(auto-fill,minmax(170px, 1fr))
      }
      @media (min-width: 481px) and (max-width: 767px) {
          margin: .5rem -.5rem;
          grid-template-columns: repeat(auto-fill,minmax(155px, 1fr));
      }
      @media (min-width: 768px) and (max-width: 991px) {
          margin: .5rem -.5rem;
          grid-template-columns: repeat(auto-fill,minmax(187px, 1fr));
      }
  } /* units-dash-home */

  .add_notes_popup {
      position: fixed;
      left: -300px;
      top: 45%;
      z-index: 9;
      background: #fff;
      border-radius: 0 0 5px 0;
      border: 1px solid #EAEAEA;
      width: 300px;
      -webkit-transition: all 0.2s ease-in-out;
      -moz-transition: all 0.2s ease-in-out;
      -o-transition: all 0.2s ease-in-out;
      transition: all 0.2s ease-in-out;
      [dir="ltr"] & {
          right: -300px;
          left: auto;
          border-radius: 0 0 0 5px;
      } /* ltr */
      &.active {
          left: 0;
          [dir="ltr"] & {
              right: 0;
              left: auto;
          } /* ltr */
          button[type="button"] {
              &::before {
                  display: block;
                  opacity: 1;
              } /* before */
          } /* button */
      } /* active */
      button[type="button"] {
          background: #fff;
          height: 45px;
          width: 45px;
          text-align: center;
          line-height: 45px;
          border-radius: 0 5px 5px 0;
          border: 1px solid #EAEAEA;
          border-left: none;
          position: absolute;
          top: -1px;
          right: -45px;
          outline: none;
          [dir="ltr"] & {
              left: -45px;
              right: auto;
              border-left: 1px solid #EAEAEA;
              border-right: none;
              border-radius: 5px 0 0 5px;
          } /* ltr */
          &::before {
              content: "";
              width: 100%;
              height: 100%;
              position: fixed;
              top: 0;
              right: 0;
              opacity: 0;
              display: none;
              -webkit-transition: all 0.2s ease-in-out;
              -moz-transition: all 0.2s ease-in-out;
              -o-transition: all 0.2s ease-in-out;
              transition: all 0.2s ease-in-out;
          } /* before */
          svg {
              display: block;
              margin: 0 auto;
          } /* svg */
      } /* button */
      .add_notes_inside {
          padding: 10px;
          .title {
              font-size: 17px;
              line-height: 25px;
          } /* title */
          .content_area {
              margin: 30px auto 0;
              position: relative;
              .icon{
                  overflow: auto;
                  position: absolute;
                  margin: 0 auto;
                  display: table;
                  top: -15px;
                  svg {
                      [dir="ltr"] & {
                          -webkit-transform: rotatey(180deg);
                          -moz-transform: rotatey(180deg);
                          -o-transform: rotatey(180deg);
                          transform: rotatey(180deg);
                      } /* ltr */
                  } /* svg */
              } /* icon */
              textarea {
                  background: #FDFB8D;
                  width: 100%;
                  border: 1px solid #E3E15C;
                  border-radius: 5px;
                  padding: 25px 10px 10px 10px;
                  color: #000;
                  font-size: 16px;
                  margin: 0 auto;
              } /* textarea */
              button {
                  background: #EE4E71;
                  -webkit-box-shadow: none;
                  box-shadow: none;
                  border: none;
                  display: inline-block;
                  width: auto;
                  padding: 0 20px;
                  width: 100%;
                  font-size: 17px;
                  height: 40px;
                  line-height: 40px;
                  outline: none;
                  &:hover {background: #DF3F62;}
              } /* button */
          } /* content_area */
      } /* add_notes_inside */
  } /* add_notes_popup */
  ::-webkit-input-placeholder {color: #000000;}
  :-moz-placeholder {color: #000000;opacity:  1;}
  ::-moz-placeholder {color: #000000;opacity:  1;}
  :-ms-input-placeholder {color: #000000;}
  ::-ms-input-placeholder {color: #000000;}
  ::placeholder {color:    #000000;}

  .reservations_awaiting_confirmation {
    border-radius: 5px;
    margin: 20px auto;
    background: #ffffff;
    border-left: 1px solid #DDDDDD;
    border-right: 1px solid #DDDDDD;
    border-bottom: 1px solid #DDDDDD;
    .title {
      display: flex;
      padding: 10px;
      border-radius: 5px 5px 0 0;
      align-items: center;
      justify-content: space-between;
      background: #9B59B6;
      span {
        display: block;
        font-size: 18px;
        color: #ffffff;
      } /* span */
      .icon {
        width: 45px;
        height: 45px;
        background-repeat: no-repeat;
