        } /* icon */
        span {
          display: block;
          font-size: 18px;
          color: #DDDDDD;
        } /* span */
      } /* no_data_show */
      .block {
        background: #FDFDFD;
        border-radius: 5px;
        border: 1px solid #ddd;
        margin: 0 auto 10px;
        padding: 5px 0;
        color: #000;
        display: flex;
        align-items: center;
        justify-content: space-around;
        cursor: pointer;
        -webkit-transition: all 0.2s ease-in-out;
        -moz-transition: all 0.2s ease-in-out;
        -o-transition: all 0.2s ease-in-out;
        transition: all 0.2s ease-in-out;
        @media (min-width: 320px) and (max-width: 767px) {
          flex-wrap: wrap;
        }
        @media (min-width: 768px) and (max-width: 991px) {
          flex-wrap: wrap;
        }
        .txt {
          flex: 1 1 0;
          padding: 0 5px;
          @media (min-width: 320px) and (max-width: 767px) {
            width: 100%;
            flex: auto;
          }
          @media (min-width: 768px) and (max-width: 991px) {
            width: 100%;
            flex: auto;
          }
          span {
            display: block;
            font-size: 15px;
            color: #000000;
          } /* span */
          ul {
            display: flex;
            align-items: center;
            justify-content: flex-start;
            flex-wrap: wrap;
            margin: 0 -5px;
            li {
              padding: 0 5px;
              min-width: 25%;
              margin: 5px 0 0;
              font-size: 13px;
              color: #000;
              @media (min-width: 320px) and (max-width: 767px) {
                width: 100%;
              }
              @media (min-width: 768px) and (max-width: 991px) {
                width: 50%;
              }
              p {
                display: inline-block;
                margin: 0 0 0 5px;
                color: #7C858E;
              } /* p */
              .price {
                display: inline-block;
                color: #0A80D8;
                font-weight: bold;
              } /* price */
            } /* li */
          } /* ul */
        } /* txt */
        .buttons_area {
          text-align: center;
          padding: 0 5px;
          @media (min-width: 320px) and (max-width: 767px) {
            margin: 10px auto 0;
            width: 100%;
          }
          @media (min-width: 768px) and (max-width: 991px) {
            margin: 10px auto 0;
            width: 100%;
          }
          button.confirmation {
            display: block;
            background: #0A80D8;
            border-radius: 4px;
            font-size: 15px;
            padding: 5px 20px;
            color: #fff;
            margin: 0 auto;
            @media (min-width: 320px) and (max-width: 767px) {
              display: inline-block;
            }
            @media (min-width: 768px) and (max-width: 991px) {
              display: inline-block;
            }
          } /* confirmation */
          button.cancellation {
            display: block;
            background: transparent;
            border-radius: 4px;
            font-size: 15px;
            padding: 5px 20px;
            color: #ff0000;
            margin: 0 auto;
            @media (min-width: 320px) and (max-width: 767px) {
              display: inline-block;
            }
            @media (min-width: 768px) and (max-width: 991px) {
              display: inline-block;
            }
          } /* cancellation */
        } /* buttons_area */
        &:hover {
          background: #f8f8f8;
          border-color: #d8d8d8;
        } /* hover */
      } /* block */
    } /* content_area */
  } /* reservations_awaiting_confirmation */

